import React from "react"
import { Link, graphql } from "gatsby"

import Layout from "../components/layout"
import SEO from "../components/seo"
import { rhythm } from "../utils/typography"

const BlogIndex = ({ data, location }) => {
  const siteTitle = data.site.siteMetadata.title
  const posts = data.allMarkdownRemark.edges
  const isDevelopment = process.env.GATSBY_ENVIRONMENT === 'development'

  return (
    <Layout location={location} title={siteTitle}>
      <SEO title="All posts" />

      <div>
        <p>
          Reflection and projects. Currently Android 
          {` `}
          <a href='https://twitter.com/expedia'>
            @expedia
          </a>
        </p>
      </div>

      {posts
        .map(({ node }) => {
          const title = node.frontmatter.title || node.fields.slug
          if ((node.frontmatter.draft === null || node.frontmatter.draft === undefined) || (node.frontmatter.draft === true && isDevelopment)) {
            return (
              <article key={node.fields.slug}>
                <header>
                  <h3
                    style={{
                      marginBottom: rhythm(1 / 4),
                    }}
                  >
                    <Link style={{ boxShadow: `none` }} to={node.fields.slug}>
                      {title}
                    </Link>
                  </h3>
                  <small>{node.frontmatter.date}</small>
                </header>
                <section>
                  <p
                    dangerouslySetInnerHTML={{
                      // __html: node.frontmatter.description || node.excerpt,
                      __html: node.excerpt,
                    }}
                  />
                </section>
              </article>
            )
          }
        })}
    </Layout>
  )
}

export default BlogIndex

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(
      filter: {fields: {category: {eq: "blog"}}}
      sort: {frontmatter: {date: DESC}}
    ) {
      edges {
        node {
          excerpt
          fields {
            category
            slug
          }
          frontmatter {
            date(formatString: "MMMM DD, YYYY")
            title
            draft
          }
        }
      }
    }
  }
`
